(function () {
  var style = document.createElement('style');
  style.textContent = [
    '.sidebar-nav > ul > li ul { display: none; }',
    '.sidebar-nav li.open > ul { display: block; }',
    '.app-sub-sidebar { display: none; }',
    '.app-sub-sidebar.open { display: block; }',
    '.active + ul.app-sub-sidebar { display: block; }'
  ].join('\n');
  document.head.appendChild(style);

  // Remember which folders are open (survives docsify re-renders)
  var openFolders = new Set();

  function getFolderKey(li) {
    var links = li.getElementsByTagName('a');
    for (var i = 0; i < links.length; i++) {
      var parent = links[i].parentNode;
      if (parent === li || (parent.tagName === 'P' && parent.parentNode === li)) {
        return links[i].getAttribute('href');
      }
    }
    return null;
  }

  function getDirectLink(li) {
    var links = li.getElementsByTagName('a');
    for (var i = 0; i < links.length; i++) {
      var parent = links[i].parentNode;
      if (parent === li || (parent.tagName === 'P' && parent.parentNode === li)) {
        return links[i];
      }
    }
    return null;
  }

  function markAndRestore() {
    document.querySelectorAll('.sidebar-nav li').forEach(function (li) {
      if (li.querySelector('ul:not(.app-sub-sidebar)')) {
        li.classList.add('folder');
        var key = getFolderKey(li);
        if (key && openFolders.has(key)) {
          li.classList.add('open');
        }
      } else {
        li.classList.add('file');
      }
    });
  }

  function applyDisplayLevel(root, level) {
    if (!root) return;
    var maxLevel = window.$docsify && window.$docsify.sidebarDisplayLevel;
    if (typeof maxLevel !== 'number') return;
    var children = root.children;
    for (var i = 0; i < children.length; i++) {
      var node = children[i];
      if (node.tagName === 'LI' && node.classList.contains('folder')) {
        if (level <= maxLevel) {
          node.classList.add('open');
          var key = getFolderKey(node);
          if (key) openFolders.add(key);
        }
        var uls = node.getElementsByTagName('ul');
        for (var j = 0; j < uls.length; j++) {
          if (uls[j].parentNode === node && !uls[j].classList.contains('app-sub-sidebar')) {
            applyDisplayLevel(uls[j], level + 1);
            break;
          }
        }
      }
    }
  }

  function openActivePath() {
    var hash = decodeURIComponent(location.hash).replace(/ /gi, '%20');
    var link = document.querySelector('.sidebar-nav a[href="' + hash + '"]');
    if (!link) return;
    var el = link.closest ? link.closest('li') : link.parentNode;
    while (el) {
      if (el.classList && el.classList.contains('sidebar-nav')) break;
      if (el.tagName === 'LI' && el.classList.contains('folder')) {
        el.classList.add('open');
        var key = getFolderKey(el);
        if (key) openFolders.add(key);
      }
      el = el.parentNode;
    }
  }

  function handleClick(e) {
    var a = e.target.closest ? e.target.closest('a') : null;
    if (!a) return;

    var li = a.closest ? a.closest('li') : null;
    if (!li || !li.classList.contains('folder')) return;

    // Only intercept clicks on the folder's own link, not nested child links
    if (a !== getDirectLink(li)) return;

    e.preventDefault();
    e.stopImmediatePropagation();

    li.classList.toggle('open');
    var key = getFolderKey(li);
    if (key) {
      if (li.classList.contains('open')) {
        openFolders.add(key);
      } else {
        openFolders.delete(key);
      }
    }
  }

  function handleScroll() {
    requestAnimationFrame(function () {
      var active = document.querySelector('.app-sub-sidebar > .active');
      if (!active) return;
      active.parentNode.parentNode.querySelectorAll('.app-sub-sidebar').forEach(function (el) {
        el.classList.remove('open');
      });
      while (active.parentNode.classList.contains('app-sub-sidebar') && !active.parentNode.classList.contains('open')) {
        active.parentNode.classList.add('open');
        active = active.parentNode;
      }
    });
  }

  document.addEventListener('scroll', handleScroll);

  // Saved scroll position — captured BEFORE docsify re-renders
  var savedSidebarScroll = 0;

  if (window.$docsify) {
    window.$docsify.plugins = (window.$docsify.plugins || []).concat([
      function (hook) {
        hook.beforeEach(function (content) {
          // Save scroll BEFORE docsify touches the sidebar
          var scroller = document.querySelector('.sidebar');
          if (scroller) savedSidebarScroll = scroller.scrollTop;
          return content;
        });
        hook.doneEach(function () {
          markAndRestore();
          applyDisplayLevel(document.querySelector('.sidebar-nav > ul'), 1);
          openActivePath();

          // Restore scroll AFTER sidebar is rebuilt
          var scroller = document.querySelector('.sidebar');
          if (scroller) {
            scroller.scrollTop = savedSidebarScroll;
            requestAnimationFrame(function () {
              scroller.scrollTop = savedSidebarScroll;
            });
          }
        });
        hook.ready(function () {
          document.querySelector('.sidebar-nav').addEventListener('click', handleClick, true);
        });
      }
    ]);
  }
})();
